1774   // Check for bitcasting of unscalable vector types.
1775   // e.g. <32 x i40> -> <40 x i32>
1776   if (NumDstElts != NumSrcElts && (NumSrcElts % NumDstElts) != 0 &&
1777       (NumDstElts % NumSrcElts) != 0)
