283   // It is safe and potentially profitable to load a vector directly:
284   // inselt undef, load Scalar, 0 --> load VecPtr
285   IRBuilder<> Builder(Load);
286   Value *CastedPtr =
287       Builder.CreatePointerBitCastOrAddrSpaceCast(SrcPtr, Builder.getPtrTy(AS));
288   Value *VecLd = Builder.CreateAlignedLoad(MinVecTy, CastedPtr, Alignment);
289   VecLd = Builder.CreateShuffleVector(VecLd, Mask);
