296 /// If we are loading a vector and then inserting it into a larger vector with
297 /// undefined elements, try to load the larger vector and eliminate the insert.
298 /// This removes a shuffle in IR and may allow combining of other loaded values.
299 bool VectorCombine::widenSubvectorLoad(Instruction &I) {
300   // Match subvector insert of fixed vector.
301   auto *Shuf = cast<ShuffleVectorInst>(&I);
302   if (!Shuf->isIdentityWithPadding())
303     return false;
304 
305   // Allow a non-canonical shuffle mask that is choosing elements from op1.
306   unsigned NumOpElts =
307       cast<FixedVectorType>(Shuf->getOperand(0)->getType())->getNumElements();
308   unsigned OpIndex = any_of(Shuf->getShuffleMask(), [&NumOpElts](int M) {
309     return M >= (int)(NumOpElts);
310   });
311 
312   auto *Load = dyn_cast<LoadInst>(Shuf->getOperand(OpIndex));
313   if (!canWidenLoad(Load, TTI))
314     return false;
315 
316   // We use minimal alignment (maximum flexibility) because we only care about
317   // the dereferenceable region. When calculating cost and creating a new op,
318   // we may use a larger value based on alignment attributes.
319   auto *Ty = cast<FixedVectorType>(I.getType());
320   Value *SrcPtr = Load->getPointerOperand()->stripPointerCasts();
321   assert(isa<PointerType>(SrcPtr->getType()) && "Expected a pointer type");
322   Align Alignment = Load->getAlign();
323   if (!isSafeToLoadUnconditionally(SrcPtr, Ty, Align(1), *DL, Load, &AC, &DT))
324     return false;
325 
326   Alignment = std::max(SrcPtr->getPointerAlignment(*DL), Alignment);
327   Type *LoadTy = Load->getType();
328   unsigned AS = Load->getPointerAddressSpace();
329 
330   // Original pattern: insert_subvector (load PtrOp)
331   // This conservatively assumes that the cost of a subvector insert into an
332   // undef value is 0. We could add that cost if the cost model accurately
333   // reflects the real cost of that operation.
334   InstructionCost OldCost =
335       TTI.getMemoryOpCost(Instruction::Load, LoadTy, Alignment, AS, CostKind);
336 
337   // New pattern: load PtrOp
338   InstructionCost NewCost =
339       TTI.getMemoryOpCost(Instruction::Load, Ty, Alignment, AS, CostKind);
340 
341   // We can aggressively convert to the vector form because the backend can
342   // invert this transform if it does not result in a performance win.
343   if (OldCost < NewCost || !NewCost.isValid())
344     return false;
345 
346   IRBuilder<> Builder(Load);
347   Value *CastedPtr =
348       Builder.CreatePointerBitCastOrAddrSpaceCast(SrcPtr, Builder.getPtrTy(AS));
349   Value *VecLd = Builder.CreateAlignedLoad(Ty, CastedPtr, Alignment);
350   replaceValue(I, *VecLd);
351   ++NumVecLoad;
352   return true;
353 }
