157 static bool canWidenLoad(LoadInst *Load, const TargetTransformInfo &TTI) {
158   // Do not widen load if atomic/volatile or under asan/hwasan/memtag/tsan.
159   // The widened load may load data from dirty regions or create data races
160   // non-existent in the source.
161   if (!Load || !Load->isSimple() || !Load->hasOneUse() ||
162       Load->getFunction()->hasFnAttribute(Attribute::SanitizeMemTag) ||
163       mustSuppressSpeculation(*Load))
164     return false;
165 
166   // We are potentially transforming byte-sized (8-bit) memory accesses, so make
167   // sure we have all of our type-based constraints in place for this target.
168   Type *ScalarTy = Load->getType()->getScalarType();
169   uint64_t ScalarSize = ScalarTy->getPrimitiveSizeInBits();
170   unsigned MinVectorSize = TTI.getMinVectorRegisterBitWidth();
171   if (!ScalarSize || !MinVectorSize || MinVectorSize % ScalarSize != 0 ||
172       ScalarSize % 8 != 0)
173     return false;
174 
175   return true;
176 }
